import React from 'react';

export default function HeapView({ data }) {
  // Defensive defaults to avoid "cannot read map" errors
  const nodesArr = Array.isArray(data?.nodes) ? data.nodes : [];
  const rootsArr = Array.isArray(data?.roots) ? data.roots : [];
  const minId = data?.min ?? null;
  const nodeMap = new Map(nodesArr.map(n => [n.id, n]));

  const renderNode = (id) => {
    const node = nodeMap.get(id);
    if (!node) return <li key={id}><em>missing node {id}</em></li>;
    return (
      <li key={id} style={{ margin: '6px 0' }}>
        <span style={{ fontWeight: minId === id ? '700' : '400' }}>
          {node.label ?? node.key} ({node.key})
        </span>
        {Array.isArray(node.children) && node.children.length > 0 && (
          <ul>
            {node.children.map(cid => renderNode(cid))}
          </ul>
        )}
      </li>
    );
  };

  if (!data) return <div>No heap data</div>;

  return (
    <div style={{ marginTop: 16 }}>
      <div><strong>Root list:</strong></div>
      {rootsArr.length === 0 ? <div>— empty —</div> : (
        <ul>
          {rootsArr.map(rid => renderNode(rid))}
        </ul>
      )}
    </div>
  );
}
